# checkers_game.py

class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.setup_board()

    def setup_board(self):
        # Place the initial pieces on the board
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece(row, col, "red")
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece(row, col, "black")

    def display(self):
        # Print the current state of the board
        for row in range(8):
            for col in range(8):
                if self.board[row][col]:
                    print(f"{self.board[row][col].color[0]} ", end="")
                else:
                    print(". ", end="")
            print()

    def get_piece(self, row, col):
        return self.board[row][col]

    def move_piece(self, from_row, from_col, to_row, to_col):
        piece = self.get_piece(from_row, from_col)
        if piece and piece.can_move(to_row, to_col):
            self.board[from_row][from_col] = None
            self.board[to_row][to_col] = piece
            piece.move_to(to_row, to_col)
        else:
            raise ValueError("Invalid move")

    def check_win(self):
        # Check if any player has won
        red_count = sum(1 for row in range(8) for col in range(8) if self.get_piece(row, col) and self.get_piece(row, col).color == "red")
        black_count = sum(1 for row in range(8) for col in range(8) if self.get_piece(row, col) and self.get_piece(row, col).color == "black")
        if red_count == 0:
            return "Black wins"
        elif black_count == 0:
            return "Red wins"
        else:
            return None

class Piece:
    def __init__(self, row, col, color):
        self.row = row
        self.col = col
        self.color = color
        self.king = False

    def move_to(self, new_row, new_col):
        self.row = new_row
        self.col = new_col

    def can_move(self, to_row, to_col):
        # Check if the piece can move to the given position
        delta_row = abs(to_row - self.row)
        delta_col = abs(to_col - self.col)
        if self.king:
            return (delta_row == 1 and delta_col == 1) or (delta_row == 2 and delta_col == 2)
        else:
            if self.color == "red":
                if to_row > self.row:
                    return False
            elif self.color == "black":
                if to_row < self.row:
                    return False
            return (delta_row == 1 and delta_col == 1) or (delta_row == 2 and delta_col == 2)

    def __repr__(self):
        if self.king:
            return f"{self.color[0]}K"
        else:
            return f"{self.color[0]}"
```

